import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";

// ── Config ──
export interface IChingAgentConfig {
  id: string;
  config_key: string;
  config_value: string;
  description: string | null;
  updated_at: string;
}

export const useIChingAgentConfigs = () =>
  useQuery({
    queryKey: ["iching-agent-configs"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("iching_agent_config")
        .select("*")
        .order("created_at");
      if (error) throw error;
      return data as IChingAgentConfig[];
    },
  });

export const useUpdateIChingAgentConfig = () => {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: async ({ id, config_value }: { id: string; config_value: string }) => {
      const { error } = await supabase
        .from("iching_agent_config")
        .update({ config_value } as any)
        .eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => qc.invalidateQueries({ queryKey: ["iching-agent-configs"] }),
  });
};

// ── Hexagrams ──
export interface IChingHexagram {
  id: string;
  number: number;
  name_zh: string;
  name_en: string | null;
  symbol: string | null;
  trigram_upper: string | null;
  trigram_lower: string | null;
  hexagram_text: string | null;
  image_text: string | null;
  judgment_text: string | null;
  line_texts: any;
  modern_interpretation: string | null;
  food_health_notes: string | null;
  tags: string[] | null;
  usage_count: number;
  updated_at: string;
}

export const useIChingHexagrams = () =>
  useQuery({
    queryKey: ["iching-hexagrams"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("iching_hexagrams")
        .select("*")
        .order("number");
      if (error) throw error;
      return data as IChingHexagram[];
    },
  });

export const useUpdateHexagram = () => {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: async (hex: Partial<IChingHexagram> & { id: string }) => {
      const { id, ...rest } = hex;
      const { error } = await supabase
        .from("iching_hexagrams")
        .update(rest as any)
        .eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => qc.invalidateQueries({ queryKey: ["iching-hexagrams"] }),
  });
};

// ── Generation History ──
export interface IChingGenerationRecord {
  id: string;
  scene_type: string;
  reference_id: string | null;
  reference_name: string | null;
  input_content: string | null;
  output_content: string;
  hexagram_number: number | null;
  hexagram_name: string | null;
  version: number;
  is_applied: boolean;
  model_used: string | null;
  created_at: string;
}

export const useIChingHistory = (sceneType?: string, referenceId?: string) =>
  useQuery({
    queryKey: ["iching-history", sceneType, referenceId],
    queryFn: async () => {
      let q = supabase
        .from("iching_generation_history")
        .select("*")
        .order("created_at", { ascending: false })
        .limit(100);
      if (sceneType) q = q.eq("scene_type", sceneType);
      if (referenceId) q = q.eq("reference_id", referenceId);
      const { data, error } = await q;
      if (error) throw error;
      return data as IChingGenerationRecord[];
    },
  });

