// ── Unified Generate ──
export interface GenerateIChingParams {
  scene_type: "store_story" | "post_neijing" | "dish_neijing";
  input_content: string;
  reference_id?: string;
  reference_name?: string;
  custom_prompt?: string;
  forbidden_hexagrams?: string[];
  stream?: boolean;
  apply_to_story?: boolean;
}

export interface GenerateIChingResult {
  success: boolean;
  output: string;
  hexagram: { name: string; number: number | null } | null;
  version: number;
  applied?: boolean;
}

export const useGenerateIChing = () => {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: async (params: GenerateIChingParams): Promise<GenerateIChingResult> => {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) throw new Error("Not authenticated");

      const resp = await fetch(
        `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/generate-iching`,
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${session.access_token}`,
            apikey: import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY,
          },
          body: JSON.stringify({ ...params, stream: false }),
        }
      );

      if (!resp.ok) {
        const errData = await resp.json().catch(() => ({ error: `HTTP ${resp.status}` }));
        throw new Error(errData.error || `HTTP ${resp.status}`);
      }

      return resp.json();
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["iching-history"] });
    },
  });
};
